class DiffusionRandomWalkParticles(Scene):
    def construct(self):
        title = Text("Diffusion Intuition", font_size=36).to_edge(UP)
        noise_label = ValueTracker(0)
        particles = VGroup(*[
            Dot(radius=0.06, color=BLUE_B).move_to(np.array([
                np.cos(i) * 0.35,
                np.sin(i) * 0.25,
                0,
            ]))
            for i in np.linspace(0, TAU, 18, endpoint=False)
        ])
        label = always_redraw(lambda: Text(
            f"Noise level: {noise_label.get_value():.1f}", font_size=26
        ).to_edge(DOWN))
        target_positions = [
            np.array([
                3.2 * np.cos(angle) + 0.5 * np.cos(3 * angle),
                1.8 * np.sin(angle),
                0,
            ])
            for angle in np.linspace(0, TAU, len(particles), endpoint=False)
        ]
        arrows = VGroup(*[
            Arrow(ORIGIN, target * 0.22, buff=0, stroke_width=2, color=GRAY_C)
            for target in target_positions[::3]
        ])
        self.play(FadeIn(title), FadeIn(particles), FadeIn(label), run_time=2)
        self.play(FadeIn(arrows), noise_label.animate.set_value(0.4), run_time=1.5)
        self.play(*[particle.animate.move_to(target) for particle, target in zip(particles, target_positions)], noise_label.animate.set_value(1.0), run_time=5)
        self.play(Indicate(particles, color=TEAL_A), run_time=1)
        self.wait(1)

